  if (x > 10) return 1.0;
  if (x < -10) return 0.0;
  if (x == 0) return 0.5;
  if (x == Double.MAX_VALUE || x == Double.MIN_VALUE) return 1.0;
  if (x == -Double.MAX_VALUE || x == -Double.MIN_VALUE) return 0.0;
  return 0.5 * (1.0 + Erf.erf((x - mean) / (standardDeviation * Math.sqrt(2.0))));
